/*
 * Splits long authored docs into one short page per `##` section, so the autogenerated sidebar nests
 * them and Docusaurus adds the prev/next pagination buttons for free.
 *
 * Source: every `docs/_<name>.mdx` (the leading `_` makes Docusaurus ignore the long source).
 * Output: `docs/<name>/` — an `index.mdx` (intro, before the first `##`) plus `NN-<slug>.mdx` per
 * section, and a `_category_.json`. The output dirs are generated (gitignored); edit the `_<name>.mdx`.
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import GithubSlugger from 'github-slugger';

const DOCS_DIR = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '../docs');
const GENERATED_NOTE = '{/* AUTO-GENERATED by scripts/split-docs.mjs from the sibling _<name>.mdx — do not edit. */}';

/** Split `---\n…\n---` frontmatter off the top → `{ data, body }` (values kept as raw strings). */
function parseFrontmatter(source) {
  const match = /^---\n([\s\S]*?)\n---\n?/.exec(source);
  if (!match) {
    return { data: {}, body: source };
  }
  const data = {};
  for (const line of match[1].split('\n')) {
    const kv = /^([\w-]+):\s*(.*)$/.exec(line);
    if (kv) {
      data[kv[1]] = kv[2];
    }
  }
  return { data, body: source.slice(match[0].length) };
}

/** Pull the leading `import …` lines out of the body; they're hoisted into every emitted page. */
function extractImports(body) {
  const imports = [];
  const rest = [];
  for (const line of body.split('\n')) {
    (/^import\s.+from\s.+$/.test(line.trim()) ? imports : rest).push(line);
  }
  return { imports, body: rest.join('\n').trim() };
}

/** Split a markdown body at each top-level `## ` heading (fenced code skipped). */
function splitSections(body) {
  const slugger = new GithubSlugger();
  const intro = [];
  const sections = [];
  let current = null;
  let inFence = false;
  for (const line of body.split('\n')) {
    if (line.trim().startsWith('```')) {
      inFence = !inFence;
    }
    const heading = !inFence && /^##\s+(.+?)\s*$/.exec(line);
    if (heading) {
      current = { title: heading[1].trim(), slug: slugger.slug(heading[1].trim()), lines: [] };
      sections.push(current);
      continue; // drop the heading line — it becomes the page's frontmatter title
    }
    (current ? current.lines : intro).push(line);
  }
  return {
    intro: intro.join('\n').trim(),
    sections: sections.map(s => ({ title: s.title, slug: s.slug, body: s.lines.join('\n').trim() })),
  };
}

/** Up-shift `###`–`######` by one level so a section's sub-headings sit under its new page H1. */
function upshiftHeadings(markdown) {
  let inFence = false;
  return markdown
    .split('\n')
    .map(line => {
      if (line.trim().startsWith('```')) {
        inFence = !inFence;
      }
      return inFence
        ? line
        : line.replace(/^(#{3,6})(\s)/, (_, hashes, space) => '#'.repeat(hashes.length - 1) + space);
    })
    .join('\n');
}

/** Rewrite in-page `](#section-slug)` links to the section's new page route. */
function rewriteAnchors(markdown, routeBySlug) {
  return markdown.replace(/\]\(#([\w-]+)\)/g, (whole, slug) =>
    routeBySlug.has(slug) ? `](${routeBySlug.get(slug)})` : whole
  );
}

function writeMdx(file, frontmatter, imports, body) {
  const fm = [
    '---',
    ...Object.entries(frontmatter)
      .filter(([, v]) => v != null)
      .map(([k, v]) => `${k}: ${v}`),
    '---',
  ].join('\n');
  const content = [fm, GENERATED_NOTE, imports.join('\n'), body].filter(Boolean).join('\n\n');
  fs.writeFileSync(file, `${content.replace(/\n{3,}/g, '\n\n').trimEnd()}\n`);
}

function splitFile(sourcePath) {
  const name = path
    .basename(sourcePath)
    .replace(/^_/, '')
    .replace(/\.mdx?$/, '');
  const { data, body: rawBody } = parseFrontmatter(fs.readFileSync(sourcePath, 'utf8'));
  const { imports, body } = extractImports(rawBody);

  // The leading `# Title` becomes the category label / index H1; drop it from the split body.
  const pageTitle = (/^#\s+(.+)$/m.exec(body)?.[1] ?? name).trim();
  const { intro, sections } = splitSections(body.replace(/^#\s+.+$/m, '').trim());

  // Sections are folder-routed at `/<name>/<slug>` (the index may override its own slug, but that
  // doesn't move the siblings). Used to rewrite in-page anchors to the split pages.
  const routeBySlug = new Map(sections.map(s => [s.slug, `/${name}/${s.slug}`]));

  const outDir = path.join(DOCS_DIR, name);
  fs.rmSync(outDir, { recursive: true, force: true });
  fs.mkdirSync(outDir, { recursive: true });

  // A `landing_section` is shown in two places: it stays a visible menu item (taking the root `slug`),
  // and its content is duplicated into the category's index page so clicking the category shows it too.
  // (Docusaurus hides a category's `link` target from the sidebar, so a link can't keep the item visible.)
  const landingSlug = data.landing_section;
  const landingSection = landingSlug ? sections.find(section => section.slug === landingSlug) : undefined;

  fs.writeFileSync(
    path.join(outDir, '_category_.json'),
    `${JSON.stringify({ label: pageTitle, position: data.sidebar_position ? Number(data.sidebar_position) : undefined }, null, 2)}\n`
  );

  // The index page is the intro, plus the landing section's content duplicated after it when present.
  const indexBody = landingSection ? [intro, upshiftHeadings(landingSection.body)].filter(Boolean).join('\n\n') : intro;
  writeMdx(
    path.join(outDir, 'index.mdx'),
    { ...(data.slug && !landingSlug ? { slug: data.slug } : {}), sidebar_position: 0, title: pageTitle },
    imports,
    rewriteAnchors(indexBody, routeBySlug)
  );

  sections.forEach((section, index) => {
    // The landing section takes the root `slug` so the site's home is the previewer. The doc intro lives
    // only on the index page, not duplicated into the section itself.
    const isLanding = landingSlug === section.slug;
    writeMdx(
      path.join(outDir, `${section.slug}.mdx`),
      { sidebar_position: index + 1, title: section.title, ...(isLanding && data.slug ? { slug: data.slug } : {}) },
      imports,
      rewriteAnchors(upshiftHeadings(section.body), routeBySlug)
    );
  });

  return { name, sections: sections.length };
}

const sources = fs.readdirSync(DOCS_DIR).filter(f => /^_.+\.mdx?$/.test(f));
for (const source of sources) {
  const { name, sections } = splitFile(path.join(DOCS_DIR, source));
  // eslint-disable-next-line no-console
  console.log(`[split-docs] ${source} → docs/${name}/ (index + ${sections} sections)`);
}
